Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <!-- Pull-to-refresh via RefreshView wrapper -->
        <CollectionView.Parent>
            <!-- See wrapped version below -->
        </CollectionView.Parent>

        <CollectionView.ItemTemplate>
            <DataTemplate>
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</ContentPage>
```

Since `CollectionView` doesn't have built-in pull-to-refresh, wrap it in a `RefreshView`:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}">
        <CollectionView.ItemTemplate>
            <DataTemplate>
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</RefreshView>
```

**ViewModel**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    // Fires when SelectedItem changes (CommunityToolkit.Mvvm convention)
    partial void OnSelectedItemChanged(Item? value)
    {
        if (value is null) return;

        // Navigate, then clear selection so user can re-select the same item
        _nav.NavigateAsync("DetailPage", new Dictionary<string, object>
        {
            { "Item", value }
        });

        SelectedItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }
}
```

**Key binding points:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `ItemsSource` | `Items` (ObservableCollection) | Drives the list |
| `SelectedItem` (TwoWay) | `SelectedItem` | Triggers navigation via `OnSelectedItemChanged` |
| `RefreshView.Command` | `RefreshCommand` | Auto-generated from `[RelayCommand]` on `RefreshAsync` |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Controls the refresh spinner |

**Important details:**
- `SelectedItem` must be **TwoWay** so the VM can reset it to `null` after navigation (allows re-selecting the same row).
- Set `IsRefreshing = false` in `finally` — `RefreshView` won't stop the spinner automatically.
- This uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`). Without it, implement `INotifyPropertyChanged` manually.
